import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "compare_event_outcome_quotes",
    args: {
      eventQuery: "Paris Saint-Germain FC vs. Liverpool FC",
      outcomes: [
        "Will Paris Saint-Germain FC win on 2026-04-08?",
        "Will Paris Saint-Germain FC vs. Liverpool FC end in a draw?",
        "Will Liverpool FC win on 2026-04-08?"
      ],
      includeHistory: false,
      limit: 3
    }
  });

  const rows = Array.isArray(result?.matchedOutcomes)
    ? result.matchedOutcomes.map((o) => ({
        matchedName: o?.matchedName,
        tokenId: o?.tokenId,
        impliedProbability: o?.impliedProbability ?? o?.yesMid ?? o?.currentPrice ?? null,
        bestBid: o?.bestBid ?? null,
        bestAsk: o?.bestAsk ?? null,
        spread: o?.spread ?? null,
        spreadCentsDisplay: o?.spreadCentsDisplay ?? null,
        spreadPercentDisplay: o?.spreadPercentDisplay ?? null,
        readableQuote: o?.readableQuote ?? null
      }))
    : [];

  return {
    eventTitle: result?.eventTitle ?? null,
    eventSlug: result?.eventSlug ?? null,
    selectionReason: result?.selectionReason ?? null,
    synthesisHint: result?.synthesisHint ?? null,
    outcomes: rows,
    unmatchedOutcomes: Array.isArray(result?.unmatchedOutcomes) ? result.unmatchedOutcomes : [],
    widestSpreadOutcome: result?.widestSpreadOutcome ?? null,
    fetchedAt: result?.fetchedAt ?? null
  };
}

