import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const query = "2026 FIFA World Cup Winner";

  const resolved = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      query,
      sortBy: "volume",
      category: "sports",
    },
  });

  const eventTitle = resolved?.eventTitle || null;
  const eventSlug = resolved?.eventSlug || null;

  const targetOutcomes = ["Spain", "France", "England", "Switzerland", "New Zealand", "South Korea"];

  const whaleBreakdown = eventSlug
    ? await callMcpSkill({
        toolId,
        toolName: "analyze_event_whale_breakdown",
        args: {
          slug: eventSlug,
          maxOutcomes: 20,
        },
      })
    : null;

  const whalesByOutcome = Array.isArray(whaleBreakdown?.whalesByOutcome)
    ? whaleBreakdown.whalesByOutcome
    : [];

  const matched = whalesByOutcome.filter((row) =>
    targetOutcomes.some((name) => String(row?.outcome || "").toLowerCase() === name.toLowerCase())
  );

  const ranked = matched
    .map((row) => ({
      outcome: row.outcome,
      totalValue: row.totalWhaleValue,
      whaleCount: row.whaleCount,
      convictionLevel: row.convictionLevel,
      currentPrice: row.currentPrice,
      holdersScanned: row.holdersScanned,
      returnedHolderSampleCount: row.returnedHolderSampleCount,
    }))
    .sort((a, b) => (b.totalValue || 0) - (a.totalValue || 0));

  const strongest = ranked[0] || null;

  return {
    eventTitle,
    eventSlug,
    sampledOutcomes: targetOutcomes,
    strongestWhaleBacking: strongest,
    sampledOutcomeComparison: ranked,
    selectionReason: whaleBreakdown?.selectionReason || null,
    smartMoneyConsensus: whaleBreakdown?.smartMoneyConsensus || null,
    totalMarketsAnalyzed: whaleBreakdown?.totalMarketsAnalyzed ?? null,
    totalMarketsInEvent: whaleBreakdown?.totalMarketsInEvent ?? null,
    fetchedAt: whaleBreakdown?.fetchedAt ...[truncated]

