export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const resolved = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      query: "US x Iran ceasefire by...?"
    }
  });

  const eventTitle = resolved?.eventTitle;
  const eventSlug = resolved?.eventSlug;
  const outcomes = Array.isArray(resolved?.outcomes) ? resolved.outcomes : [];

  const liveBuckets = outcomes
    .filter((o) => o && typeof o === "object")
    .map((o) => ({
      name: o.name,
      price: o.price,
      volume: o.volume,
      conditionId: o.conditionId,
      tokenId: o.tokenId
    }))
    .filter((o) => typeof o.name === "string");

  const rankedByProbability = [...liveBuckets].sort((a, b) => (b.price ?? -1) - (a.price ?? -1));
  const rankedByVolume = [...liveBuckets].sort((a, b) => (b.volume ?? -1) - (a.volume ?? -1));

  return {
    eventTitle,
    eventSlug,
    liveBuckets,
    highestQuotedProbability: rankedByProbability[0] || null,
    mostVolume: rankedByVolume[0] || null,
    note: "This is based on the live event data returned by the past query; I’m not assuming any additional bucket end dates beyond what the tool resolved."
  };
}

